import SwiftUIstruct EditTransactionView: View {    @StateObject private var vm: EditTransactionViewModel    @Environment(\.dismiss) var dismiss    let onSaved: (() -> Void)?        init(isExpense: Bool, onSaved: (() -> Void)? = nil) {        self.onSaved = onSaved        _vm = StateObject(wrappedValue: EditTransactionViewModel(isExpense: isExpense))    }    var body: some View {        NavigationStack {            VStack(spacing: 20) {                // СЧЁТ                VStack(alignment: .leading, spacing: 6) {                    Text("Счёт")                        .font(.headline)                    Picker("Счёт", selection: $vm.selectedAccountId) {                        ForEach(vm.accounts) { acc in                            Text("\(acc.name) — \(acc.amount.money)")                                .tag(Optional(acc.id))                        }                    }                    .pickerStyle(.menu)                }                // КАТЕГОРИЯ                VStack(alignment: .leading, spacing: 6) {                    Text("Категория")                        .font(.headline)                    NavigationLink {                        CategoryPickerView(                            selected: $vm.selectedCategory,                            type: vm.isExpense ? .expense : .income                        )                    } label: {                        HStack {                            Text(vm.selectedCategory?.name ?? "Выбрать")                                .foregroundColor(vm.selectedCategory == nil ? .secondary : .primary)                            Spacer()                            Image(systemName: "chevron.right")                                .foregroundColor(.secondary)                        }                        .padding()                        .background(Color(.secondarySystemBackground))                        .cornerRadius(10)                    }                }                // СУММА                VStack(alignment: .leading, spacing: 6) {                    Text("Сумма")                        .font(.headline)                    TextField("0", value: $vm.amount, format: .number)                        .keyboardType(.decimalPad)                        .padding()                        .background(Color(.secondarySystemBackground))                        .cornerRadius(10)                }                // ОПИСАНИЕ                VStack(alignment: .leading, spacing: 6) {                    Text("Описание")                        .font(.headline)                    TextField("Комментарий", text: $vm.description)                        .padding()                        .background(Color(.secondarySystemBackground))                        .cornerRadius(10)                }                // ДАТА                VStack(alignment: .leading, spacing: 6) {                    Text("Дата")                        .font(.headline)                    DatePicker("", selection: $vm.date, displayedComponents: .date)                        .datePickerStyle(.compact)                        .labelsHidden()                }                Spacer()                Button {                    Task {                        try await vm.save()                        dismiss()                    }                } label: {                    Text("Сохранить")                        .font(.headline)                        .foregroundColor(.white)                        .frame(maxWidth: .infinity)                        .padding()                        .background(Color.blue)                        .cornerRadius(12)                }                .padding(.bottom, 20)            }            .padding()            .navigationTitle(vm.isExpense ? "Добавить расход" : "Добавить доход")            .toolbar {                ToolbarItem(placement: .topBarLeading) {                    Button { dismiss() } label: {                        Image(systemName: "chevron.left")                    }                }            }            .task { await vm.load() }        }    }}